.status-card__row {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  margin-bottom: 10px;
}

.progress-bar {
  height: 12px;
  border-radius: 999px;
  background: hsl(0 0% 100% / 0.08);
  overflow: hidden;
  margin: 14px 0 18px;
}

.progress-bar__fill {
  height: 100%;
  background: linear-gradient(90deg, var(--accent) 0%, var(--accent-strong) 100%);
}

.result-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 16px;
  margin-top: 20px;
}

.viewer-layout {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(320px, 380px) minmax(320px, 380px);
  gap: 16px;
  margin-top: 20px;
}

.card--map,
.card--viewer {
  display: flex;
  flex-direction: column;
}

.canvas-frame {
  position: relative;
  margin-top: 14px;
  border-radius: 18px;
  overflow: hidden;
  background: var(--canvas-surface);
  border: 1px solid var(--border);
}

.canvas {
  display: block;
  width: 100%;
  height: auto;
  background: var(--canvas-surface);
}

.canvas--map {
  max-height: 480px;
  object-fit: contain;
}

.canvas--viewer {
  aspect-ratio: 1 / 1;
}

.canvas-frame--mandelbrot {
  background: var(--canvas-mandelbrot);
}

.canvas--mandelbrot {
  aspect-ratio: 3 / 2;
}

.mandelbrot-crosshair {
  position: absolute;
  width: 36px;
  height: 36px;
  transform: translate(-50%, -50%);
  filter: var(--crosshair-filter);
  pointer-events: none;
}

.metric {
  margin: 8px 0 0;
  font-weight: 600;
}

.metric--large {
  font-size: 1.4rem;
  line-height: 1.3;
}

.detail {
  margin: 8px 0 0;
  font-size: 0.92rem;
}

.ok {
  color: var(--ok);
}

.errors,
.notes {
  margin: 12px 0 0;
  padding-left: 18px;
}

.error-banner {
  margin: 12px 0 0;
  color: var(--error);
  font-weight: 600;
}

.settings-summary {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 16px;
  margin-top: 22px;
}

.theme-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 16px;
}

.theme-card {
  width: 100%;
  display: grid;
  gap: 14px;
  padding: 16px;
  border-radius: 22px;
  border: 1px solid var(--border);
  background: var(--surface);
  color: inherit;
  cursor: pointer;
  text-align: left;
  box-shadow: 0 16px 38px var(--shadow-color);
  transition:
    transform 140ms ease,
    border-color 140ms ease,
    box-shadow 140ms ease;
}

.theme-card:hover,
.theme-card:focus-visible {
  transform: translateY(-3px);
  border-color: hsl(0 0% 100% / 0.2);
}

.theme-card--selected {
  border-color: var(--accent);
  box-shadow:
    0 16px 38px var(--shadow-color),
    0 0 0 1px var(--accent) inset;
}

.theme-card__preview {
  padding: 14px;
  border-radius: 18px;
  border: 1px solid var(--border);
  background-color: var(--page-background);
  background-image: var(--page-background-image);
  box-shadow: inset 0 0 0 1px hsl(0 0% 100% / 0.04);
}

.theme-card__meta {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 12px;
}

.theme-card__meta strong {
  display: block;
  font-size: 1rem;
}

.theme-card__badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 64px;
  min-height: 30px;
  padding: 0 10px;
  border-radius: 999px;
  background: var(--surface-strong);
  border: 1px solid var(--border);
  color: var(--muted);
  text-transform: capitalize;
  font-size: 0.76rem;
}

.theme-card__badge--selected {
  background: linear-gradient(135deg, var(--accent) 0%, var(--accent-strong) 100%);
  color: white;
  border-color: transparent;
}

.theme-preview {
  display: grid;
  gap: 10px;
  min-height: 176px;
  padding: 12px;
  border-radius: 16px;
  border: 1px solid var(--border);
  background: var(--surface);
  box-shadow: 0 12px 28px var(--shadow-color);
  backdrop-filter: blur(12px);
}

.theme-preview__masthead {
  display: flex;
  gap: 8px;
}

.theme-preview__pill {
  width: 42px;
  height: 10px;
  border-radius: 999px;
  background: var(--surface-muted);
}

.theme-preview__pill--accent {
  background: var(--accent);
}

.theme-preview__pill--strong {
  background: var(--accent-strong);
}

.theme-preview__body {
  display: grid;
  grid-template-columns: 54px minmax(0, 1fr);
  gap: 10px;
}

.theme-preview__sidebar,
.theme-preview__panel,
.theme-preview__hero,
.theme-preview__canvas {
  border: 1px solid var(--border);
  background: var(--surface-strong);
}

.theme-preview__sidebar {
  display: grid;
  gap: 8px;
  align-content: start;
  padding: 10px;
  border-radius: 12px;
}

.theme-preview__line {
  display: block;
  height: 8px;
  border-radius: 999px;
  background: var(--surface-muted);
}

.theme-preview__line--short {
  width: 68%;
}

.theme-preview__content {
  display: grid;
  gap: 10px;
}

.theme-preview__hero {
  min-height: 44px;
  border-radius: 12px;
  background:
    linear-gradient(135deg, var(--accent) 0%, var(--accent-strong) 100%);
}

.theme-preview__row {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.theme-preview__panel {
  min-height: 38px;
  border-radius: 12px;
}

.theme-preview__panel--accent {
  background:
    linear-gradient(135deg, var(--surface-strong) 0%, hsl(0 0% 100% / 0.04) 100%),
    linear-gradient(135deg, var(--accent) 0%, var(--accent-strong) 100%);
}

.theme-preview__canvas {
  min-height: 48px;
  border-radius: 12px;
  background:
    linear-gradient(135deg, hsl(0 0% 100% / 0.03), hsl(0 0% 100% / 0.01)),
    var(--canvas-mandelbrot);
}

@media (max-width: 1280px) {
  .theme-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 1100px) {
  .app-shell {
    grid-template-columns: 1fr;
  }

  .result-grid {
    grid-template-columns: 1fr;
  }

  .viewer-layout {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 860px) {
  .app-page {
    padding: 14px;
  }

  .topbar {
    flex-direction: column;
    align-items: stretch;
  }

  .topbar__nav {
    width: 100%;
  }

  .nav-link {
    flex: 1 1 0;
  }

  .settings-summary,
  .theme-grid {
    grid-template-columns: 1fr;
  }
}

